// OAuth Configuration
const OAuthConfig = {
  clientId: 'YOUR_CLIENT_ID',
  clientSecret: 'YOUR_CLIENT_SECRET',
  authorizationEndpoint: 'https://oauth-provider.com/oauth/authorize',
  tokenEndpoint: 'https://oauth-provider.com/oauth/token',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write',
  state: null
};

// Generate random state for CSRF protection
function generateRandomState() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
}

// Generate code verifier and challenge for PKCE
function generateCodeVerifier() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return base64URLEncode(array);
}

async function generateCodeChallenge(verifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(verifier);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return base64URLEncode(new Uint8Array(hash));
}

function base64URLEncode(buffer) {
  const base64 = btoa(String.fromCharCode.apply(null, buffer));
  return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

// OAuth Manager
const OAuthManager = {
  initiateAuthorization: async function() {
    const state = generateRandomState();
    const codeVerifier = generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(codeVerifier);
    
    localStorage.setItem('oauth_state', state);
    localStorage.setItem('code_verifier', codeVerifier);
    
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAuthConfig.clientId,
      redirect_uri: OAuthConfig.redirectUri,
      scope: OAuthConfig.scope,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256'
    });
    
    window.location.href = `${OAuthConfig.authorizationEndpoint}?${params.toString()}`;
  },
  
  handleCallback: async function() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const error = urlParams.get('error');
    
    if (error) {
      throw new Error(`OAuth error: ${error}`);
    }
    
    const storedState = localStorage.getItem('oauth_state');
    if (state !== storedState) {
      throw new Error('State mismatch - possible CSRF attack');
    }
    
    if (!code) {
      throw new Error('No authorization code received');
    }
    
    const codeVerifier = localStorage.getItem('code_verifier');
    await this.exchangeCodeForToken(code, codeVerifier);
    
    localStorage.removeItem('oauth_state');
    localStorage.removeItem('code_verifier');
    
    window.history.replaceState({}, document.title, '/');
  },
  
  exchangeCodeForToken: async function(code, codeVerifier) {
    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAuthConfig.redirectUri,
      client_id: OAuthConfig.clientId,
      client_secret: OAuthConfig.clientSecret,
      code_verifier: codeVerifier
    });
    
    const response = await fetch(OAuthConfig.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });
    
    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(`Token exchange failed: ${errorData.error_description || errorData.error}`);
    }
    
    const tokenData = await response.json();
    this.storeTokens(tokenData);
    return tokenData;
  },
  
  storeTokens: function(tokenData) {
    localStorage.setItem('access_token', tokenData.access_token);
    if (tokenData.refresh_token) {
      localStorage.setItem('refresh_token', tokenData.refresh_token);
    }
    if (tokenData.expires_in) {
      const expiresAt = Date.now() + (tokenData.expires_in * 1000);
      localStorage.setItem('token_expires_at', expiresAt.toString());
    }
    if (tokenData.token_type) {
      localStorage.setItem('token_type', tokenData.token_type);
    }
  },
  
  getAccessToken: function() {
    return localStorage.getItem('access_token');
  },
  
  getRefreshToken: function() {
    return localStorage.getItem('refresh_token');
  },
  
  isTokenExpired: function() {
    const expiresAt = localStorage.getItem('token_expires_at');
    if (!expiresAt) return true;
    return Date.now() >= parseInt(expiresAt);
  },
  
  refreshAccessToken: async function() {
    const refreshToken = this.getRefreshToken();
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }
    
    const params = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAuthConfig.clientId,
      client_secret: OAuthConfig.clientSecret
    });
    
    const response = await fetch(OAuthConfig.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });
    
    if (!response.ok) {
      this.clearTokens();
      throw new Error('Token refresh failed');
    }
    
    const tokenData = await response.json();
    this.storeTokens(tokenData);
    return tokenData;
  },
  
  clearTokens: function() {
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    localStorage.removeItem('token_expires_at');
    localStorage.removeItem('token_type');
  },
  
  logout: function() {
    this.clearTokens();
    window.location.href = '/';
  },
  
  isAuthenticated: function() {
    return !!this.getAccessToken() && !this.isTokenExpired();
  }
};

// API Client with automatic token refresh
const APIClient = {
  makeAuthenticatedRequest: async function(url, options = {}) {
    if (OAuthManager.isTokenExpired()) {
      try {
        await OAuthManager.refreshAccessToken();
      } catch (error) {
        OAuthManager.logout();
        throw error;
      }
    }
    
    const accessToken = OAuthManager.getAccessToken();
    const tokenType = localStorage.getItem('token_type') || 'Bearer';
    
    const headers = {
      ...options.headers,
      'Authorization': `${tokenType} ${accessToken}`
    };
    
    const response = await fetch(url, {
      ...options,
      headers
    });
    
    if (response.status === 401) {
      try {
        await OAuthManager.refreshAccessToken();
        const newAccessToken = OAuthManager.getAccessToken();
        headers['Authorization'] = `${tokenType} ${newAccessToken}`;
        return await fetch(url, { ...options, headers });
      } catch (error) {
        OAuthManager.logout();
        throw error;
      }
    }
    
    return response;
  },
  
  get: async function(url, options = {}) {
    return this.makeAuthenticatedRequest(url, { ...options, method: 'GET' });
  },
  
  post: async function(url, data, options = {}) {
    return this.makeAuthenticatedRequest(url, {
      ...options,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...options.headers
      },
      body: JSON.stringify(data)
    });
  },
  
  put: async function(url, data, options = {}) {
    return this.makeAuthenticatedRequest(url, {
      ...options,
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        ...options.headers
      },
      body: JSON.stringify(data)
    });
  },
  
  delete: async function(url, options = {}) {
    return this.makeAuthenticatedRequest(url, { ...options, method: 'DELETE' });
  }
};

